// Phase 1 — Declaration: 'status' slot created in env record
// Phase 2 — Memory:     'status' slot reserved
// Phase 3 — Init (var): 'status' set to undefined
console.log(status); // undefined (var is pre-initialised)

var status = 'active'; // Phase 4 — Assignment: 'active' written
console.log(status);   // 'active'

// --- let example ---
// console.log(level); //  ReferenceError: Cannot access 'level' before initialization (TDZ)
let level = 5;         // Declaration + Initialization + Assignment all happen here
console.log(level);    // 5

6_edge_case.code:
// Attempting to separate declaration and assignment for const:
try {
  eval('const score; score = 100;'); // SyntaxError: Missing initializer in const declaration
} catch (e) {
  console.log(e.constructor.name + ': ' + e.message);
}

// The full lifecycle for const is collapsed into a single statement:
const maxScore = 100; // declare + allocate + initialize + assign all at once
